Javascript.logic:
var opt = Services.getValue(NewAddressForService.dataBinding);

Services.setValue( NewAddL3.dataBinding, "");

if( 'ACK' == opt && null != solNode )
{	var ad3N = solNode.selectSingleNode("./ContactDetails/Address/Line[3]")
	if( null != ad3N)
	{ Services.setValue(NewAddL3.dataBinding, XML.getNodeTextContent(ad3N ));}
}
else if( 'ADDR' == opt && null != defNode )
{	Services.setValue(NewAddL3.dataBinding, XML.getNodeTextContent( defNode.selectSingleNode("./ContactDetails/Address/Line[3]")));
}
